async function seed() {
  let storeId = process.argv[2];

  if (!storeId) {
    const { data: stores, error } = await supabase
      .from('stores')
      .select('id, store_name')
      .limit(10);

    if (error || !stores?.length) {
      console.error('❌ Could not find any stores:', error?.message);
      process.exit(1);
    }

    if (stores.length === 1) {
      storeId = stores[0].id;
      console.log(`Using store: "${stores[0].store_name}" (${storeId})`);
    } else {
      console.log('Multiple stores found. Pass a store_id as an argument:\n');
      stores.forEach((s) =>
        console.log(
          `  node scripts/seed-products.js ${s.id}  # ${s.store_name}`,
        ),
      );
      process.exit(0);
    }
  }

  // Fetch ALL existing products for global sync
  console.log('Fetching all products from database...');
  const { data: existingProducts, error: fetchError } = await supabase
    .from('products')
    .select('*');

  if (fetchError) {
    console.error('❌ Error fetching existing products:', fetchError.message);
    process.exit(1);
  }

  // Create maps for efficient lookup
  // Normalization: trim, lowercase, spaces to hyphens
  const normalize = (n) => n.trim().toLowerCase().replace(/\s+/g, '-');
  
  const skuMap = new Map(existingProducts.map((p) => [p.sku, p]));
  const nameMap = new Map();
  existingProducts.forEach(p => {
    const key = normalize(p.name);
    // If multiple products have same name, we'll just map to the first one found
    // or we could handle per store, but for description update, global is fine
    if (!nameMap.has(key)) nameMap.set(key, p);
  });

  console.log(`Processing ${PRODUCTS.length} products against ${existingProducts.length} items in DB...`);

  let updated = 0;
  let skipped = 0;

  for (let i = 0; i < PRODUCTS.length; i++) {
    const p = PRODUCTS[i];
    const normalizedName = normalize(p.name);
    
    // Try to find by normalized name or SKU
    const existing = nameMap.get(normalizedName) || skuMap.get(p.sku);

    if (existing) {
      const productData = {
        description: p.description || null,
        how_to_use: p.how_to_use || null,
        ingredients: p.ingredients || null,
      };

      // Only update if fields are actually different or null in DB
      const needsUpdate = !existing.description || !existing.how_to_use || !existing.ingredients;
      
      if (needsUpdate || true) { // Force update for now to ensure consistency
        const { error: updateError } = await supabase
          .from('products')
          .update(productData)
          .eq('id', existing.id);

        if (updateError) {
          console.error(`❌ Error updating "${existing.name}" (${existing.id}):`, updateError.message);
        } else {
          console.log(`  ✓ Updated: ${existing.name}`);
          updated++;
        }
      } else {
        skipped++;
      }
    } else {
      skipped++;
    }
  }

  console.log(`\n✅ Done! Updated: ${updated}, Skipped/Not found: ${skipped}`);
}

seed();
